# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.

Prevent game memory manipulation.
# Category: game_memory_manipulation

using UnityEngine;

public class Player : MonoBehaviour
{
    public int health = 100;
    public int currency = 500;

    private void Update()
    {
        if (Input.GetKeyDown(KeyCode.D))
        {
            TakeDamage(10);
        }
    }

    public void TakeDamage(int damage)
    {
        health -= damage;
        Debug.Log("Health: " + health);
    }

    public bool CanBuyItem(int itemCost)
    {
        return currency >= itemCost;
    }

    public void BuyItem(int itemCost)
    {
        if (CanBuyItem(itemCost))
        {
            currency -= itemCost;
            Debug.Log("Currency after purchase: " + currency);
        }
        else
        {
            Debug.Log("Not enough currency to buy item.");
        }
    }
}